import axios from 'axios';

const API_BASE_URL = 'http://localhost:8080/api';

const api = axios.create({
  baseURL: API_BASE_URL,
});

// Add request interceptor to include auth token
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('token');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// Auth APIs
export const login = (email, password) => api.post('/auth/login', { email, password });
export const register = (employeeId, fullName, email, password, role) =>
  api.post('/auth/register', { employeeId, fullName, email, password, role });

// Employee APIs
export const getEmployees = () => api.get('/employees');

// Attendance APIs
export const getAttendance = () => api.get('/attendance');
export const postAttendance = (data) => api.post('/attendance', data);

// Leave APIs
export const getLeaves = () => api.get('/leaves');
export const postLeave = (data) => api.post('/leaves', data);
export const putLeave = (id, data) => api.put(`/leaves/${id}`, data);
export const deleteLeave = (id) => api.delete(`/leaves/${id}`);

// Payroll APIs
export const getPayroll = () => api.get('/payroll');

export default api;
